{
  "compilerOptions": {
    "strict": true
  }
}

// Ciddi rejim olmadan
function greet(name) {
  return `Hello, ${name}!`;
}

console.log(greet('Alice')); // Hello, Alice!
console.log(greet()); // Hello, undefined!

// Ciddi rejim ilə
function greet(name: string) {
  return `Hello, ${name}!`;
}

console.log(greet('Alice')); // Hello, Alice!
// console.log(greet()); // Xəta: An argument for 'name' was not provided
// console.log(greet(null)); // Xəta: Argument of type 'null' is not assignable to parameter of type 'string'

// noImplicitAny ilə
function processValue(value: string) {
  return value.toUpperCase();
}

console.log(processValue('hello')); // HELLO
// function processInvalid(value) { // Xəta: Parameter 'value' implicitly has an 'any' type
//   return value;
// }

// strictNullChecks ilə
function getLength(text: string) {
  return text.length;
}

console.log(getLength('hello')); // 5
// console.log(getLength(null)); // Xəta: Argument of type 'null' is not assignable to parameter of type 'string'

// Ciddi rejim ilə
function add(a: number, b: number): number {
  return a + b;
}

console.log(add(5, 10)); // 15
// console.log(add('5', 10)); // Xəta: Argument of type 'string' is not assignable to parameter of type 'number'

// Tip təhlükəsizliyi ilə
interface User {
  name: string;
  age: number;
}

function printUser(user: User) {
  console.log(`Name: ${user.name}, Age: ${user.age}`);
}

const user = { name: 'Alice', age: 25 };
printUser(user); // Name: Alice, Age: 25
// printUser({ name: 'Bob' }); // Xəta: Property 'age' is missing
// printUser({ name: 'Bob', age: '30' }); // Xəta: Type 'string' is not assignable to type 'number'

// Ciddi rejim ilə səhvə yol açan nümunə
function divide(a: number, b: number): number {
  return a / b;
}

console.log(divide(10, 2)); // 5
// console.log(divide(10, 0)); // Xəta: Sıfıra bölmə aşkarlanmayıb, lakin icra zamanı problem ola bilər
// console.log(divide('10', 2)); // Xəta: Argument of type 'string' is not assignable to parameter of type 'number'

// Real layihə ssenarisi
interface Product {
  id: number;
  name: string;
  price: number;
}

function displayProduct(product: Product) {
  console.log(`Product: ${product.name}, Price: ${product.price}`);
}

const product = { id: 1, name: 'Laptop', price: 1000 };
displayProduct(product); // Product: Laptop, Price: 1000
// displayProduct({ id: '1', name: 'Phone' }); // Xəta: Property 'price' is missing, Type 'string' is not assignable to type 'number'

