function getLength(text: string) {
  return text.length;
}

console.log(getLength('hello')); // 5
// console.log(getLength(null)); // Ошибка: Тип 'null' не может быть присвоен параметру типа 'string'

// Со строгим режимом
function add(a: number, b: number): number {
  return a + b;
}

console.log(add(5, 10)); // 15
// console.log(add('5', 10)); // Ошибка: Тип 'string' не может быть присвоен параметру типа 'number'

// С безопасностью типов
interface User {
  name: string;
  age: number;
}

function printUser(user: User) {
  console.log(`Name: ${user.name}, Age: ${user.age}`);
